ALTER TABLE public.companies
  ADD COLUMN IF NOT EXISTS address text,
  ADD COLUMN IF NOT EXISTS lat double precision,
  ADD COLUMN IF NOT EXISTS lng double precision,
  ADD COLUMN IF NOT EXISTS neighborhood text;

ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, description = EXCLUDED.description, address = EXCLUDED.address,
  lat = EXCLUDED.lat, lng = EXCLUDED.lng, neighborhood = EXCLUDED.neighborhood,
  hero_image_url = EXCLUDED.hero_image_url, city = EXCLUDED.city;

-- Clear old demo history then drop the old demo offers
DELETE FROM public.cart_items WHERE offer_id IN (SELECT id FROM public.offers WHERE provider_company_id::text LIKE '22222222-%');
DELETE FROM public.request_items WHERE offer_id IN (SELECT id FROM public.offers WHERE provider_company_id::text LIKE '22222222-%');
DELETE FROM public.requests WHERE id NOT IN (SELECT DISTINCT request_id FROM public.request_items);
DELETE FROM public.offers WHERE provider_company_id::text LIKE '22222222-%';

ON CONFLICT (id) DO UPDATE SET
  title = EXCLUDED.title, description = EXCLUDED.description, price_all = EXCLUDED.price_all,
  image_url = EXCLUDED.image_url, location = EXCLUDED.location, is_seasonal = EXCLUDED.is_seasonal, tags = EXCLUDED.tags;